package com.google.gson;
import com.google.gson.internal.Streams;
import com.google.gson.stream.JsonWriter;
import java.io.IOException;
import java.io.StringWriter;
import java.math.BigDecimal;
import java.math.BigInteger;

import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

import java.lang.reflect.InvocationHandler;
import java.lang.reflect.Method;
import java.lang.reflect.Proxy;

class JsonElementTest {

  private static class JsonElementSubclass extends JsonElement {
    @Override
    public JsonElement deepCopy() {
      return this;
    }
  }

  @Test
  void testIsJsonObject_withJsonObjectInstance_returnsTrue() {
    // Create a proxy instance that extends JsonElement and implements JsonObject
    JsonElement element = (JsonElement) Proxy.newProxyInstance(
      JsonElement.class.getClassLoader(),
      new Class<?>[] { JsonObject.class },
      new InvocationHandler() {
        @Override
        public Object invoke(Object proxy, Method method, Object[] args) throws Throwable {
          if ("deepCopy".equals(method.getName())) {
            return proxy;
          }
          if ("isJsonObject".equals(method.getName())) {
            return true;
          }
          // fallback to default behavior for other methods
          if (method.getReturnType() == boolean.class) {
            return false;
          }
          return null;
        }
      }
    );

    // isJsonObject() checks instanceof JsonObject, so proxy must implement JsonObject
    assertTrue(element.isJsonObject());
  }

  @Test
  void testIsJsonObject_withJsonElementInstance_returnsFalse() {
    JsonElement element = new JsonElementSubclass();
    assertFalse(element.isJsonObject());
  }

}
